std::uintmax_t file_size_or_zero(const std::filesystem::path& path) {
    std::error_code ec;
    const auto size = std::filesystem::file_size(path, ec);
    return ec ? 0 : size;
}

int run_export_archive(const std::filesystem::path& repo_root, const std::string& output_arg, bool validate_release_archive) {
    auto root = git_repo_root(repo_root).value_or(repo_root);
    std::error_code ec;
    root = std::filesystem::weakly_canonical(root, ec);
    if (ec) {
        root = std::filesystem::absolute(root).lexically_normal();
    }

    const auto head = git_capture_command(root, {"rev-parse", "--verify", "HEAD"});
    if (!head || trim_copy(*head).empty()) {
        std::cerr << "export: Git HEAD is required to create a release archive\n";
        return 1;
    }

    auto rev_output = git_capture_command(root, {"rev-list", "--count", "HEAD"});
    std::string revision = rev_output ? trim_copy(*rev_output) : "0";
    if (revision.empty()) {
        revision = "0";
    }

    const auto repo_name = root.filename().string().empty() ? std::string("repo") : root.filename().string();
    std::filesystem::path archive_path;
    if (!output_arg.empty()) {
        auto output_path = expand_user_path(output_arg);
        if (output_path.is_relative()) {
            output_path = root / output_path;
        }
        const auto ext = lower_copy(output_path.extension().string());
        if (ext == ".tar") {
            archive_path = output_path;
        } else {
            archive_path = output_path / (repo_name + "_Rev" + revision + ".tar");
        }
    } else {
        archive_path = root / "_archives" / (repo_name + "_Rev" + revision + ".tar");
    }

    std::filesystem::create_directories(archive_path.parent_path());

    std::cout << "Creating archive: " << archive_path.filename().string() << "\n";
    std::cout << "Repository: " << repo_name << "\n";
    std::cout << "Revision: " << revision << "\n";

    if (validate_release_archive) {
        const auto hygiene_rc = run_repo_hygiene(root, false, true);
        if (hygiene_rc != 0) {
            std::cerr << "export: release archive validation failed before archive creation\n";
            return hygiene_rc;
        }
    }

    const auto archive_rc = git_system_command(root, {"archive", "--format=tar", "--output", archive_path.string(), "HEAD"});
    if (archive_rc != 0) {
        std::cerr << "export: git archive failed with code " << archive_rc << "\n";
        return 1;
    }

    const auto size = file_size_or_zero(archive_path);
    if (validate_release_archive && size == 0) {
        std::cerr << "export: archive is empty: " << archive_path.string() << "\n";
        return 1;
    }

    std::cout << "Archive created: " << archive_path.string() << "\n";
    std::cout << "Size bytes: " << size << "\n";
    return 0;
}

std::vector<std::string> git_history_paths(const std::filesystem::path& repo_root) {
    const auto command = "git -C " + shell_quote_arg(repo_root.string()) + " rev-list --all --objects" + shell_null_redirect();
    auto output = run_capture_command(command);
    std::vector<std::string> paths;
    if (!output) {
        return paths;
    }
    std::istringstream input(*output);
    std::string line;
    while (std::getline(input, line)) {
        line = trim_copy(line);
        const auto space = line.find(' ');
        if (space != std::string::npos && space + 1 < line.size()) {
            paths.push_back(trim_copy(line.substr(space + 1)));
        }
    }
    return paths;
}

std::optional<std::string> git_last_commit_for_path(const std::filesystem::path& repo_root, const std::string& path) {
    const auto command = "git -C " + shell_quote_arg(repo_root.string()) + " log -n 1 --format=%H -- " +
        shell_quote_arg(path) + shell_null_redirect();
    auto output = run_capture_command(command);
    if (!output) {
        return std::nullopt;
    }
    auto commit = trim_copy(*output);
    return commit.empty() ? std::nullopt : std::optional<std::string>(commit);
}

std::optional<std::string> git_show_file(const std::filesystem::path& repo_root, const std::string& commit, const std::string& path) {
    const auto spec = commit + ":" + path;
    const auto command = "git -C " + shell_quote_arg(repo_root.string()) + " show " + shell_quote_arg(spec) + shell_null_redirect();
    auto output = run_capture_command(command);
    if (!output) {
        return std::nullopt;
    }
    return *output;
}

LinkRestoreResultNative restore_links_from_vcs_native(
    const std::filesystem::path& product_root,
    const std::filesystem::path& backlog_root,
    bool include_views,
    const std::vector<std::string>& ignore_targets,
    const std::vector<std::pair<std::string, std::string>>& remap_roots,
    bool apply
) {
    LinkRestoreResultNative result;
    result.product = product_root.filename().string();

    int checked_files = 0;
    const auto issues = collect_link_issues_native(product_root, backlog_root, include_views, ignore_targets, &checked_files);
    result.checked_files = checked_files;

    const auto repo_root = git_repo_root(backlog_root);
    if (!repo_root) {
        for (const auto& issue : issues) {
            result.actions.push_back(LinkRestoreActionNative{issue.source_path, issue.target, "no-vcs", {}, std::nullopt});
        }
        return result;
    }

    const auto history_paths = git_history_paths(*repo_root);
    for (const auto& issue : issues) {
        auto target = normalize_path_fragment(drop_fragment(issue.target));
        if (target.empty() || matches_ignore_target(target, ignore_targets)) {
            continue;
        }

        auto candidates = match_history_candidates(target, history_paths);
        std::sort(candidates.begin(), candidates.end());
        candidates.erase(std::unique(candidates.begin(), candidates.end()), candidates.end());
        if (candidates.empty()) {
            result.actions.push_back(LinkRestoreActionNative{issue.source_path, issue.target, "missing", {}, std::nullopt});
            continue;
        }

        std::map<std::string, std::vector<std::string>> remapped_map;
        for (const auto& candidate : candidates) {
            remapped_map[apply_remap_to_path(candidate, remap_roots)].push_back(candidate);
        }
        if (remapped_map.size() > 1) {
            result.actions.push_back(LinkRestoreActionNative{issue.source_path, issue.target, "ambiguous", candidates, std::nullopt});
            continue;
        }

        const auto remapped_target = remapped_map.begin()->first;
        const auto& original_candidates = remapped_map.begin()->second;
        auto history_path = original_candidates.front();
        for (const auto& candidate : original_candidates) {
            if (starts_with(normalize_path_fragment(candidate), normalize_path_fragment(remapped_target))) {
                history_path = candidate;
                break;
            }
        }

        const auto commit = git_last_commit_for_path(*repo_root, history_path);
        if (!commit) {
            result.actions.push_back(LinkRestoreActionNative{issue.source_path, issue.target, "missing", candidates, std::nullopt});
            continue;
        }

        const auto restore_path = *repo_root / remapped_target;
        if (std::filesystem::exists(restore_path)) {
            result.actions.push_back(LinkRestoreActionNative{issue.source_path, issue.target, "exists", candidates, restore_path.string()});
            continue;
        }
        if (!is_inside_path(restore_path, *repo_root)) {
            result.actions.push_back(LinkRestoreActionNative{issue.source_path, issue.target, "unsafe-target", candidates, std::nullopt});
            continue;
        }

        const auto file_text = git_show_file(*repo_root, *commit, history_path);
        if (!file_text) {
            result.actions.push_back(LinkRestoreActionNative{issue.source_path, issue.target, "missing", candidates, std::nullopt});
            continue;
        }

        const auto status = apply ? "restored" : "would-restore";
        if (apply) {
            write_text_file(restore_path, *file_text);
        }
        result.actions.push_back(LinkRestoreActionNative{issue.source_path, issue.target, status, candidates, restore_path.string()});
    }

    return result;
}

std::vector<std::string> split_lines_for_rewrite(const std::string& text) {
    std::vector<std::string> lines;
    std::istringstream input(text);
    std::string line;
    while (std::getline(input, line)) {
        if (!line.empty() && line.back() == '\r') {
            line.pop_back();
        }
        lines.push_back(line);
    }
    return lines;
}

std::string join_lines_with_final_newline(const std::vector<std::string>& lines) {
    std::ostringstream output;
    for (const auto& line : lines) {
        output << line << "\n";
    }
    return output.str();
}

bool is_id_boundary_char(char ch) {
    const unsigned char uch = static_cast<unsigned char>(ch);
    return !(std::isalnum(uch) || ch == '-');
}

std::string replace_id_tokens(const std::string& text, const std::string& old_id, const std::string& new_id) {
    if (old_id.empty()) {
        return text;
    }
    std::string out;
    std::size_t cursor = 0;
    while (cursor < text.size()) {
        const auto pos = text.find(old_id, cursor);
        if (pos == std::string::npos) {
            out.append(text.substr(cursor));
            break;
        }
        const bool left_ok = pos == 0 || is_id_boundary_char(text[pos - 1]);
        const auto after = pos + old_id.size();
        const bool right_ok = after >= text.size() || is_id_boundary_char(text[after]);
        if (left_ok && right_ok) {
            out.append(text.substr(cursor, pos - cursor));
            out.append(new_id);
            cursor = after;
        } else {
            out.append(text.substr(cursor, after - cursor));
            cursor = after;
        }
    }
    return out;
}

std::string replace_id_tokens_excluding_worklog(const std::string& text, const std::string& old_id, const std::string& new_id) {
    auto lines = split_lines_for_rewrite(text);
    std::optional<std::size_t> worklog_index;
    for (std::size_t i = 0; i < lines.size(); ++i) {
        if (trim_copy(lines[i]) == "# Worklog") {
            worklog_index = i;
            break;
        }
    }
    if (!worklog_index) {
        return replace_id_tokens(text, old_id, new_id);
    }

    std::vector<std::string> head(lines.begin(), lines.begin() + static_cast<std::ptrdiff_t>(*worklog_index));
    std::vector<std::string> tail(lines.begin() + static_cast<std::ptrdiff_t>(*worklog_index), lines.end());
    auto updated_head = replace_id_tokens(join_lines_with_final_newline(head), old_id, new_id);
    if (!head.empty() && !updated_head.empty() && updated_head.back() == '\n') {
        updated_head.pop_back();
    }
    auto tail_text = join_lines_with_final_newline(tail);
    if (!updated_head.empty()) {
        return updated_head + "\n" + tail_text;
    }
    return tail_text;
}

int replace_id_in_files_native(
    const std::vector<std::filesystem::path>& paths,
    const std::string& old_id,
    const std::string& new_id,
    bool skip_worklog,
    bool apply
) {
    int updated_files = 0;
    for (const auto& path : paths) {
        if (!std::filesystem::exists(path)) {
            continue;
        }
        const auto text = read_text_file_path(path);
        const auto updated = skip_worklog
            ? replace_id_tokens_excluding_worklog(text, old_id, new_id)
            : replace_id_tokens(text, old_id, new_id);
        if (updated != text) {
            ++updated_files;
            if (apply) {
                write_text_file(path, updated);
            }
        }
    }
    return updated_files;
}

std::string replace_all_copy(std::string value, const std::string& old_text, const std::string& new_text) {
    if (old_text.empty()) {
        return value;
    }
    std::size_t pos = 0;
    while ((pos = value.find(old_text, pos)) != std::string::npos) {
        value.replace(pos, old_text.size(), new_text);
        pos += new_text.size();
    }
    return value;
}

std::string rewrite_replace_target_markdown_line(
    const std::string& line,
    const std::string& old_id,
    const std::string& new_rel,
    const std::string& new_stem,
    bool& file_changed
) {
    const std::regex markdown_link_re(R"(\[[^\]]+\]\(([^)]+)\))");
    std::string output;
    std::size_t cursor = 0;
    for (std::sregex_iterator it(line.begin(), line.end(), markdown_link_re), end; it != end; ++it) {
        const auto match_pos = static_cast<std::size_t>(it->position(0));
        const auto match_len = static_cast<std::size_t>(it->length(0));
        output.append(line.substr(cursor, match_pos - cursor));

        if (match_pos > 0 && line[match_pos - 1] == '!') {
            output.append(it->str(0));
            cursor = match_pos + match_len;
            continue;
        }

        const auto raw_target = (*it)[1].str();
        if (raw_target.find(old_id) == std::string::npos) {
            output.append(it->str(0));
            cursor = match_pos + match_len;
            continue;
        }
        const auto split = split_target_and_suffix(raw_target);
        auto base = drop_fragment(split.target);
        std::string fragment;
        const auto hash = split.target.find('#');
        if (hash != std::string::npos) {
            fragment = split.target.substr(hash);
        }

        std::string new_target;
        if (base == old_id || ends_with(base, "/" + old_id) || ends_with(base, "\\" + old_id) || has_path_separator(base)) {
            new_target = new_rel + fragment;
        } else {
            new_target = replace_all_copy(base, old_id, new_stem) + fragment;
        }
        const auto updated_target = rebuild_target(new_target, split.suffix, split.is_angle);
        auto replacement = it->str(0);
        const auto raw_pos = replacement.find(raw_target);
        if (raw_pos != std::string::npos) {
            replacement.replace(raw_pos, raw_target.size(), updated_target);
        }
        file_changed = true;
        output.append(replacement);
        cursor = match_pos + match_len;
    }
    output.append(line.substr(cursor));
    return output;
}

std::string rewrite_replace_target_wikilink_line(
    const std::string& line,
    const std::string& old_id,
    const std::string& new_rel,
    const std::string& new_stem,
    bool& file_changed
) {
    const std::regex wikilink_re(R"(\[\[([^\]]+)\]\])");
    std::string output;
    std::size_t cursor = 0;
    for (std::sregex_iterator it(line.begin(), line.end(), wikilink_re), end; it != end; ++it) {
        const auto match_pos = static_cast<std::size_t>(it->position(0));
        const auto match_len = static_cast<std::size_t>(it->length(0));
        output.append(line.substr(cursor, match_pos - cursor));

        const auto raw = trim_copy((*it)[1].str());
        if (raw.find(old_id) == std::string::npos) {
            output.append(it->str(0));
            cursor = match_pos + match_len;
            continue;
        }
        const auto pipe = raw.find('|');
        const auto target = trim_copy(raw.substr(0, pipe));
        const auto alias = pipe == std::string::npos ? std::string{} : trim_copy(raw.substr(pipe + 1));
        const auto new_target = (has_path_separator(target) || starts_with(target, ".")) ? new_rel : new_stem;
        auto replacement = "[[" + new_target;
        if (!alias.empty()) {
            replacement += "|" + alias;
        }
        replacement += "]]";
        file_changed = true;
        output.append(replacement);
        cursor = match_pos + match_len;
    }
    output.append(line.substr(cursor));
    return output;
}

int replace_link_targets_native(
    const std::vector<std::filesystem::path>& paths,
    const std::string& old_id,
    const std::filesystem::path& new_path,
    bool apply
) {
    int updated_files = 0;
    for (const auto& path : paths) {
        if (!std::filesystem::exists(path)) {
            continue;
        }
        auto lines = split_lines_for_rewrite(read_text_file_path(path));
        const auto new_rel = relpath_posix(path.parent_path(), new_path);
        const auto new_stem = new_path.stem().string();
        bool file_changed = false;

        for (auto& line : lines) {
            auto rewritten = rewrite_replace_target_markdown_line(line, old_id, new_rel, new_stem, file_changed);
            rewritten = rewrite_replace_target_wikilink_line(rewritten, old_id, new_rel, new_stem, file_changed);
            line = rewritten;
        }

        if (file_changed) {
            ++updated_files;
            if (apply) {
                write_text_file(path, join_lines_with_final_newline(lines));
            }
        }
    }
    return updated_files;
}

std::string next_reference_id_native(const std::filesystem::path& root, const std::string& prefix) {
    const std::regex pattern(prefix + R"(-(\d{4}))");
    int max_num = 0;
    if (std::filesystem::exists(root)) {
        for (const auto& entry : std::filesystem::directory_iterator(root)) {
            if (!entry.is_regular_file() || entry.path().extension() != ".md") {
                continue;
            }
            std::smatch match;
            const auto name = entry.path().filename().string();
            if (std::regex_search(name, match, pattern)) {
                try {
                    max_num = std::max(max_num, std::stoi(match[1].str()));
                } catch (...) {
                }
            }
        }
    }
    std::ostringstream out;
    out << prefix << "-" << std::setfill('0') << std::setw(4) << (max_num + 1);
    return out.str();
}

std::optional<std::filesystem::path> product_root_for_reference_path(
    const std::filesystem::path& target_path,
    const std::optional<std::filesystem::path>& explicit_backlog_root,
    const std::string& product
) {
    if (explicit_backlog_root && !product.empty()) {
        const auto product_root = *explicit_backlog_root / "products" / product;
        if (std::filesystem::exists(product_root)) {
            return product_root;
        }
    }

    auto current = target_path.parent_path();
    while (!current.empty() && current != current.parent_path()) {
        if (current.filename() == "decisions" && std::filesystem::exists(current.parent_path() / "items")) {
            return current.parent_path();
        }
        current = current.parent_path();
    }
    return std::nullopt;
}

struct RefRemapResultNative {
    std::string old_id;
    std::string new_id;
    std::filesystem::path old_path;
    std::filesystem::path new_path;
    int updated_files = 0;
};

RefRemapResultNative remap_reference_id_native(
    const std::filesystem::path& raw_target_path,
    const std::optional<std::filesystem::path>& explicit_backlog_root,
    const std::string& product,
    const std::string& prefix,
    bool update_refs,
    bool apply
) {
    const auto target_path = normalized_absolute_path(raw_target_path);
    if (!std::filesystem::exists(target_path)) {
        throw std::runtime_error("Target not found: " + target_path.string());
    }
    const auto product_root = product_root_for_reference_path(target_path, explicit_backlog_root, product);
    if (!product_root) {
        throw std::runtime_error("Could not resolve product root for reference remap");
    }

    const auto stem = target_path.stem().string();
    const auto underscore = stem.find('_');
    const auto old_id = underscore == std::string::npos ? stem : stem.substr(0, underscore);
    const auto suffix = underscore == std::string::npos ? std::string{} : stem.substr(underscore);
    const auto new_id = next_reference_id_native(*product_root / "decisions", prefix);
    const auto new_path = target_path.parent_path() / (new_id + suffix + target_path.extension().string());

    RefRemapResultNative result{old_id, new_id, target_path, new_path, 0};
    if (!apply) {
        return result;
    }

    if (std::filesystem::exists(new_path) && normalized_absolute_path(new_path) != target_path) {
        throw std::runtime_error("Refusing to overwrite existing reference file: " + new_path.string());
    }

    auto content = read_text_file_path(target_path);
    content = replace_id_tokens(content, old_id, new_id);
    write_text_file(new_path, content);
    if (normalized_absolute_path(new_path) != target_path) {
        std::filesystem::remove(target_path);
    }
    ++result.updated_files;

    if (update_refs) {
        for (const auto& path : list_link_markdown_paths(*product_root, false)) {
            if (normalized_absolute_path(path) == normalized_absolute_path(new_path)) {
                continue;
            }
            const auto text = read_text_file_path(path);
            const auto updated = replace_id_tokens(text, old_id, new_id);
            if (updated != text) {
                write_text_file(path, updated);
                ++result.updated_files;
            }
        }
    }

    return result;
}

Json::Value link_fix_results_to_json(const std::vector<LinkFixResultNative>& results) {
    Json::Value root(Json::arrayValue);
    for (const auto& result : results) {
        Json::Value obj(Json::objectValue);
        obj["product"] = result.product;
        obj["checked_files"] = result.checked_files;
        obj["updated_files"] = result.updated_files;
        Json::Value changes(Json::arrayValue);
        for (const auto& change : result.changes) {
            Json::Value item(Json::objectValue);
            item["source_path"] = change.source_path.string();
            item["line"] = change.line;
            item["column"] = change.column;
            item["link_type"] = change.link_type;
            item["original"] = change.original;
            item["updated"] = change.updated;
            item["reason"] = change.reason;
            changes.append(item);
        }
        obj["changes"] = changes;
        root.append(obj);
    }
    return root;
}

Json::Value link_restore_results_to_json(const std::vector<LinkRestoreResultNative>& results) {
    Json::Value root(Json::arrayValue);
    for (const auto& result : results) {
        Json::Value obj(Json::objectValue);
        obj["product"] = result.product;
        obj["checked_files"] = result.checked_files;
        Json::Value actions(Json::arrayValue);
        for (const auto& action : result.actions) {
            Json::Value item(Json::objectValue);
            item["source_path"] = action.source_path.string();
            item["target"] = action.target;
            item["status"] = action.status;
            Json::Value candidates(Json::arrayValue);
            for (const auto& candidate : action.candidates) {
                candidates.append(candidate);
            }
            item["candidates"] = candidates;
            item["restored_path"] = action.restored_path ? Json::Value(*action.restored_path) : Json::Value(Json::nullValue);
            actions.append(item);
        }
        obj["actions"] = actions;
        root.append(obj);
    }
    return root;
}

std::string optional_text(const std::optional<std::string>& value) {
    return value ? *value : "";
}

std::string join_worklog_lines(const std::vector<std::string>& lines) {
    std::ostringstream out;
    for (const auto& line : lines) {
        if (!trim_copy(line).empty()) {
            out << line << "\n";
        }
    }
    return out.str();
}

Json::Value string_array_json(const std::vector<std::string>& values) {
    Json::Value array(Json::arrayValue);
    for (const auto& value : values) {
        array.append(value);
    }
    return array;
}

Json::Value item_frontmatter_json(const BacklogItem& item, const std::optional<std::string>& parent_uid = std::nullopt) {
    Json::Value front(Json::objectValue);
    front["uid"] = item.uid;
    front["id"] = item.id;
    front["type"] = to_string(item.type);
    front["state"] = to_string(item.state);
    front["title"] = item.title;
    front["priority"] = optional_text(item.priority);
    if (item.parent) front["parent"] = *item.parent;
    else front["parent"] = Json::Value(Json::nullValue);
    if (parent_uid) front["parent_uid"] = *parent_uid;
    else front["parent_uid"] = Json::Value(Json::nullValue);
    front["owner"] = optional_text(item.owner);
    front["area"] = optional_text(item.area);
    front["iteration"] = optional_text(item.iteration);
    front["tags"] = string_array_json(item.tags);
    front["created"] = item.created;
    front["updated"] = item.updated;
    return front;
}

Json::Value effective_config_json_for_context(const BacklogContext& ctx) {
    Json::Value root(Json::objectValue);

    Json::Value context(Json::objectValue);
    context["project_root"] = ctx.project_root.string();
    context["backlog_root"] = ctx.backlog_root.string();
    context["product_root"] = ctx.product_root.string();
    context["product_name"] = ctx.product_name;
    context["is_sandbox"] = ctx.is_sandbox;
    if (ctx.sandbox_root) {
        context["sandbox_root"] = ctx.sandbox_root->string();
    } else {
        context["sandbox_root"] = Json::Value(Json::nullValue);
    }
    root["context"] = context;

    Json::Value config(Json::objectValue);
    Json::Value product(Json::objectValue);
    product["name"] = ctx.product_def.name.empty() ? ctx.product_name : ctx.product_def.name;
    product["prefix"] = ctx.product_def.prefix;
    product["backlog_root"] = ctx.product_def.backlog_root;
    product["default_assignee"] = optional_text(ctx.product_def.default_assignee);
    product["default_bug_reviewer"] = optional_text(ctx.product_def.default_bug_reviewer);
    product["topics_date_prefix_policy"] = ctx.product_def.topics_date_prefix_policy.empty()
        ? "warn"
        : ctx.product_def.topics_date_prefix_policy;
    config["product"] = product;

    Json::Value embedding(Json::objectValue);
    embedding["provider"] = ctx.product_def.embedding_provider.value_or("noop");
    embedding["model"] = ctx.product_def.embedding_model.value_or("noop-embedding");
    embedding["dimension"] = ctx.product_def.embedding_dimension.value_or(1536);
    config["embedding"] = embedding;

    Json::Value chunking(Json::objectValue);
    chunking["target_tokens"] = ctx.product_def.chunking_target_tokens.value_or(256);
    chunking["max_tokens"] = ctx.product_def.chunking_max_tokens.value_or(512);
    config["chunking"] = chunking;

    Json::Value tokenizer(Json::objectValue);
    tokenizer["adapter"] = ctx.product_def.tokenizer_adapter.value_or("auto");
    tokenizer["model"] = ctx.product_def.tokenizer_model.value_or("text-embedding-3-small");
    config["tokenizer"] = tokenizer;

    Json::Value vector(Json::objectValue);
    vector["enabled"] = ctx.product_def.vector_enabled.value_or(false);
    vector["backend"] = ctx.product_def.vector_backend.value_or("sqlite");
    vector["metric"] = ctx.product_def.vector_metric.value_or("cosine");
    config["vector"] = vector;

    root["config"] = config;
    return root;
}

std::string canonical_chunks_schema_sql() {
    return R"sql(
CREATE TABLE IF NOT EXISTS schema_meta (
  key TEXT PRIMARY KEY,
  value TEXT NOT NULL
);
INSERT OR REPLACE INTO schema_meta(key, value) VALUES('schema_version', '0');
CREATE TABLE IF NOT EXISTS items (
  uid TEXT PRIMARY KEY,
  id TEXT NOT NULL,
  type TEXT NOT NULL,
  state TEXT NOT NULL,
  title TEXT NOT NULL,
  path TEXT NOT NULL UNIQUE,
  mtime REAL NOT NULL,
  content_hash TEXT,
  frontmatter TEXT,
  created TEXT NOT NULL,
  updated TEXT NOT NULL,
  priority TEXT,
  parent_uid TEXT,
  owner TEXT,
  area TEXT,
  iteration TEXT,
  tags TEXT
);
CREATE INDEX IF NOT EXISTS idx_items_type ON items(type);
CREATE INDEX IF NOT EXISTS idx_items_state ON items(state);
CREATE INDEX IF NOT EXISTS idx_items_parent_uid ON items(parent_uid);
CREATE INDEX IF NOT EXISTS idx_items_priority ON items(priority);
CREATE INDEX IF NOT EXISTS idx_items_area ON items(area);
CREATE INDEX IF NOT EXISTS idx_items_mtime ON items(mtime);
CREATE INDEX IF NOT EXISTS idx_items_id ON items(id);
CREATE TABLE IF NOT EXISTS chunks (
  chunk_id TEXT PRIMARY KEY,
  parent_uid TEXT NOT NULL,
  chunk_index INTEGER NOT NULL,
  content TEXT NOT NULL,
  section TEXT,
  embedding BLOB,
  UNIQUE(parent_uid, chunk_index),
  FOREIGN KEY (parent_uid) REFERENCES items(uid) ON DELETE CASCADE
);
CREATE INDEX IF NOT EXISTS idx_chunks_parent_uid ON chunks(parent_uid);
CREATE INDEX IF NOT EXISTS idx_chunks_section ON chunks(section);
CREATE VIRTUAL TABLE IF NOT EXISTS chunks_fts USING fts5(
  chunk_id UNINDEXED,
  parent_uid UNINDEXED,
  content,
  section UNINDEXED,
  content='chunks',
  content_rowid='rowid'
);
CREATE TRIGGER IF NOT EXISTS chunks_fts_insert AFTER INSERT ON chunks BEGIN
  INSERT INTO chunks_fts(rowid, chunk_id, parent_uid, content, section)
  VALUES (new.rowid, new.chunk_id, new.parent_uid, new.content, new.section);
END;
CREATE TRIGGER IF NOT EXISTS chunks_fts_delete AFTER DELETE ON chunks BEGIN
  DELETE FROM chunks_fts WHERE rowid = old.rowid;
END;
CREATE TRIGGER IF NOT EXISTS chunks_fts_update AFTER UPDATE ON chunks BEGIN
  DELETE FROM chunks_fts WHERE rowid = old.rowid;
  INSERT INTO chunks_fts(rowid, chunk_id, parent_uid, content, section)
  VALUES (new.rowid, new.chunk_id, new.parent_uid, new.content, new.section);
END;
)sql";
}

struct SqliteHandle {
    sqlite3* db = nullptr;
    explicit SqliteHandle(const std::filesystem::path& path) {
        std::filesystem::create_directories(path.parent_path());
        if (sqlite3_open(path.string().c_str(), &db) != SQLITE_OK) {
            std::string message = db ? sqlite3_errmsg(db) : "unknown error";
            if (db) sqlite3_close(db);
            db = nullptr;
            throw std::runtime_error("Failed to open SQLite DB: " + message);
        }
    }
    ~SqliteHandle() {
        if (db) sqlite3_close(db);
    }
    SqliteHandle(const SqliteHandle&) = delete;
    SqliteHandle& operator=(const SqliteHandle&) = delete;
};

void sqlite_exec_checked(sqlite3* db, const std::string& sql) {
    char* error = nullptr;
    const int rc = sqlite3_exec(db, sql.c_str(), nullptr, nullptr, &error);
    if (rc != SQLITE_OK) {
        std::string message = error ? error : sqlite3_errmsg(db);
        if (error) sqlite3_free(error);
        throw std::runtime_error("SQLite exec failed: " + message);
    }
}

void sqlite_bind_text_checked(sqlite3_stmt* stmt, int index, const std::string& value) {
    if (sqlite3_bind_text(stmt, index, value.c_str(), -1, SQLITE_TRANSIENT) != SQLITE_OK) {
        throw std::runtime_error("SQLite bind text failed");
    }
}

void sqlite_bind_optional_text_checked(sqlite3_stmt* stmt, int index, const std::optional<std::string>& value) {
    if (value) {
        sqlite_bind_text_checked(stmt, index, *value);
    } else if (sqlite3_bind_null(stmt, index) != SQLITE_OK) {
        throw std::runtime_error("SQLite bind null failed");
    }
}

void sqlite_step_done_checked(sqlite3* db, sqlite3_stmt* stmt) {
    const int rc = sqlite3_step(stmt);
    if (rc != SQLITE_DONE) {
        throw std::runtime_error("SQLite statement failed: " + std::string(sqlite3_errmsg(db)));
    }
}

void insert_native_item_row(
    sqlite3* db,
    const std::string& uid,
    const std::string& id,
    const std::string& type,
    const std::string& state,
    const std::string& title,
    const std::string& path,
    const std::string& frontmatter,
    const std::string& created,
    const std::string& updated,
    const std::optional<std::string>& priority,
    const std::optional<std::string>& parent_uid,
    const std::optional<std::string>& owner,
    const std::optional<std::string>& area,
    const std::optional<std::string>& iteration,
    const std::string& tags_json
) {
    const char* sql =
        "INSERT INTO items (uid, id, type, state, title, path, mtime, content_hash, frontmatter, "
        "created, updated, priority, parent_uid, owner, area, iteration, tags) "
        "VALUES (?, ?, ?, ?, ?, ?, ?, NULL, ?, ?, ?, ?, ?, ?, ?, ?, ?)";
    sqlite3_stmt* stmt = nullptr;
    if (sqlite3_prepare_v2(db, sql, -1, &stmt, nullptr) != SQLITE_OK) {
        throw std::runtime_error("SQLite prepare item insert failed: " + std::string(sqlite3_errmsg(db)));
    }
    try {
        sqlite_bind_text_checked(stmt, 1, uid);
        sqlite_bind_text_checked(stmt, 2, id);
        sqlite_bind_text_checked(stmt, 3, type);
        sqlite_bind_text_checked(stmt, 4, state);
        sqlite_bind_text_checked(stmt, 5, title);
        sqlite_bind_text_checked(stmt, 6, path);
        sqlite3_bind_double(stmt, 7, 0.0);
        sqlite_bind_text_checked(stmt, 8, frontmatter);
        sqlite_bind_text_checked(stmt, 9, created);
        sqlite_bind_text_checked(stmt, 10, updated);
        sqlite_bind_optional_text_checked(stmt, 11, priority);
        sqlite_bind_optional_text_checked(stmt, 12, parent_uid);
        sqlite_bind_optional_text_checked(stmt, 13, owner);
        sqlite_bind_optional_text_checked(stmt, 14, area);
        sqlite_bind_optional_text_checked(stmt, 15, iteration);
        sqlite_bind_text_checked(stmt, 16, tags_json);
        sqlite_step_done_checked(db, stmt);
        sqlite3_finalize(stmt);
    } catch (...) {
        sqlite3_finalize(stmt);
        throw;
    }
}

void insert_native_chunk_row(
    sqlite3* db,
    const std::string& chunk_id,
    const std::string& parent_uid,
    int chunk_index,
    const std::string& content,
    const std::string& section
) {
    const char* sql = "INSERT INTO chunks (chunk_id, parent_uid, chunk_index, content, section, embedding) VALUES (?, ?, ?, ?, ?, NULL)";
    sqlite3_stmt* stmt = nullptr;
    if (sqlite3_prepare_v2(db, sql, -1, &stmt, nullptr) != SQLITE_OK) {
        throw std::runtime_error("SQLite prepare chunk insert failed: " + std::string(sqlite3_errmsg(db)));
    }
    try {
        sqlite_bind_text_checked(stmt, 1, chunk_id);
        sqlite_bind_text_checked(stmt, 2, parent_uid);
        sqlite3_bind_int(stmt, 3, chunk_index);
        sqlite_bind_text_checked(stmt, 4, content);
        sqlite_bind_text_checked(stmt, 5, section);
        sqlite_step_done_checked(db, stmt);
        sqlite3_finalize(stmt);
    } catch (...) {
        sqlite3_finalize(stmt);
        throw;
    }
}

std::vector<std::pair<std::string, std::string>> native_item_sections(const BacklogItem& item) {
    std::vector<std::pair<std::string, std::string>> sections;
    sections.push_back({"title", item.title});
    const std::vector<std::pair<std::string, std::optional<std::string>>> optionals = {
        {"context", item.context},
        {"goal", item.goal},
        {"non_goals", item.non_goals},
        {"intent_amendments", item.intent_amendments},
        {"approach", item.approach},
        {"alternatives", item.alternatives},
        {"acceptance_criteria", item.acceptance_criteria},
        {"risks", item.risks},
    };
    for (const auto& [section, value] : optionals) {
        if (value && !trim_copy(*value).empty()) {
            sections.push_back({section, *value});
        }
    }
    const auto worklog = join_worklog_lines(item.worklog);
    if (!trim_copy(worklog).empty()) {
        sections.push_back({"worklog", worklog});
    }
    return sections;
}

std::string bounded_text(std::optional<std::string> value, std::size_t max_chars) {
    if (!value) {
        return "";
    }
    std::string text = trim_copy(*value);
    if (text.size() <= max_chars) {
        return text;
    }
    if (max_chars <= 3) {
        return text.substr(0, max_chars);
    }
    return text.substr(0, max_chars - 3) + "...";
}

Json::Value intent_stack_item_json(const IntentStackEntry& entry, std::size_t max_section_chars) {
    const auto& item = entry.item;
    Json::Value row(Json::objectValue);
    row["depth"] = entry.depth;
    row["role"] = entry.role;
    row["id"] = item.id;
    row["uid"] = item.uid;
    row["type"] = to_string(item.type);
    row["title"] = item.title;
    row["state"] = to_string(item.state);
    row["parent"] = item.parent ? Json::Value(*item.parent) : Json::Value(Json::nullValue);
    row["context"] = bounded_text(item.context, max_section_chars);
    row["goal"] = bounded_text(item.goal, max_section_chars);
    row["approach"] = bounded_text(item.approach, max_section_chars);
    row["acceptance_criteria"] = bounded_text(item.acceptance_criteria, max_section_chars);
    row["risks"] = bounded_text(item.risks, max_section_chars);
    row["non_goals"] = bounded_text(item.non_goals, max_section_chars);
    row["intent_amendments"] = bounded_text(item.intent_amendments, max_section_chars);
    return row;
}

Json::Value intent_stack_json(const IntentStackResult& stack, std::size_t max_section_chars) {
    Json::Value payload(Json::objectValue);
    payload["status"] = stack.warnings.empty() ? "complete" : "warning";
    payload["chain"] = Json::Value(Json::arrayValue);
    for (const auto& entry : stack.chain) {
        payload["chain"].append(intent_stack_item_json(entry, max_section_chars));
    }
    payload["warnings"] = Json::Value(Json::arrayValue);
    for (const auto& warning : stack.warnings) {
        payload["warnings"].append(warning);
    }
    payload["evidence_refs"] = Json::Value(Json::arrayValue);
    for (const auto& ref : stack.evidence_refs) {
        payload["evidence_refs"].append(ref);
    }
    payload["query_plan"]["mode"] = "deterministic-parent-chain";
    payload["query_plan"]["semantic_retrieval"] = "external-provider-only";
    payload["query_plan"]["requires_human_confirmation"] = !stack.evidence_refs.empty();
    return payload;
}

Json::Value work_order_admission_json(const WorkOrderAdmissionResult& result) {
    Json::Value payload(Json::objectValue);
    payload["item_id"] = result.item_id;
    payload["item_type"] = result.item_type;
    payload["requested_intent"] = result.requested_intent;
    payload["effective_intent"] = result.effective_intent;
    payload["admitted"] = result.admitted;
    payload["reason_code"] = result.reason_code;
    payload["message"] = result.message;
    payload["requires_explicit_intent"] = result.requires_explicit_intent;
    payload["would_create_work_order"] = result.would_create_work_order;
    payload["would_dispatch"] = result.would_dispatch;
    payload["starts_agent"] = result.starts_agent;
    payload["dispatches_work"] = result.dispatches_work;
    payload["candidate_children"] = Json::Value(Json::arrayValue);
    for (const auto& child : result.candidate_children) {
        Json::Value row(Json::objectValue);
        row["id"] = child.id;
        row["type"] = child.type;
        row["state"] = child.state;
        row["title"] = child.title;
        row["work_intent"] = child.work_intent;
        row["recommendation"] = child.recommendation;
        payload["candidate_children"].append(row);
    }
    return payload;
}

void print_work_order_admission_text(const WorkOrderAdmissionResult& result) {
    std::cout << "# Work Order Admission\n\n";
    std::cout << "item_id: " << result.item_id << "\n";
    std::cout << "item_type: " << result.item_type << "\n";
    std::cout << "requested_intent: " << (result.requested_intent.empty() ? "<missing>" : result.requested_intent) << "\n";
    std::cout << "effective_intent: " << (result.effective_intent.empty() ? "<none>" : result.effective_intent) << "\n";
    std::cout << "admitted: " << (result.admitted ? "true" : "false") << "\n";
    std::cout << "reason_code: " << result.reason_code << "\n";
    std::cout << "message: " << result.message << "\n";
    std::cout << "requires_explicit_intent: " << (result.requires_explicit_intent ? "true" : "false") << "\n";
    std::cout << "would_create_work_order: " << (result.would_create_work_order ? "true" : "false") << "\n";
    std::cout << "would_dispatch: " << (result.would_dispatch ? "true" : "false") << "\n";
    std::cout << "starts_agent: " << (result.starts_agent ? "true" : "false") << "\n";
    std::cout << "dispatches_work: " << (result.dispatches_work ? "true" : "false") << "\n";
    std::cout << "\n## Candidate Children\n";
    if (result.candidate_children.empty()) {
        std::cout << "- none\n";
        return;
    }
    for (const auto& child : result.candidate_children) {
        std::cout << "- " << child.id << " (" << child.type << ", state=" << child.state << ", work_intent=" << (child.work_intent.empty() ? "<none>" : child.work_intent) << ")\n";
        std::cout << "  title: " << child.title << "\n";
        std::cout << "  recommendation: " << child.recommendation << "\n";
    }
}

void print_intent_stack_text(const IntentStackResult& stack, std::size_t max_section_chars) {
    std::cout << "# Intent Stack\n\n";
    std::cout << "status: " << (stack.warnings.empty() ? "complete" : "warning") << "\n";
    for (const auto& warning : stack.warnings) {
        std::cout << "warning: " << warning << "\n";
    }
    std::cout << "\n## Chain\n";
    for (const auto& entry : stack.chain) {
        const auto& item = entry.item;
        std::cout << "\n- depth: " << entry.depth << "\n";
        std::cout << "  role: " << entry.role << "\n";
        std::cout << "  id: " << item.id << "\n";
        std::cout << "  type: " << to_string(item.type) << "\n";
        std::cout << "  title: " << item.title << "\n";
        std::cout << "  parent: " << (item.parent ? *item.parent : "null") << "\n";
        if (const auto text = bounded_text(item.context, max_section_chars); !text.empty()) {
            std::cout << "  context: " << text << "\n";
        }
        if (const auto text = bounded_text(item.goal, max_section_chars); !text.empty()) {
            std::cout << "  goal: " << text << "\n";
        }
        if (const auto text = bounded_text(item.non_goals, max_section_chars); !text.empty()) {
            std::cout << "  non_goals: " << text << "\n";
        }
        if (const auto text = bounded_text(item.intent_amendments, max_section_chars); !text.empty()) {
            std::cout << "  intent_amendments: " << text << "\n";
        }
    }
    if (!stack.evidence_refs.empty()) {
        std::cout << "\n## Evidence refs\n";
        for (const auto& ref : stack.evidence_refs) {
            std::cout << "- " << ref << "\n";
        }
    }
    std::cout << "\n## Query Plan\n";
    std::cout << "- mode: deterministic-parent-chain\n";
    std::cout << "- semantic_retrieval: external-provider-only\n";
}

Json::Value intent_template_json(
    const IntentStackResult& stack,
    const std::string& template_kind,
    std::size_t max_section_chars
) {
    Json::Value payload(Json::objectValue);
    payload["kind"] = template_kind;
    payload["intent_stack"] = intent_stack_json(stack, max_section_chars);

    Json::Value preflight(Json::objectValue);
    preflight["intent_trace"] = Json::Value(Json::arrayValue);
    preflight["inherited_do_not"] = Json::Value(Json::arrayValue);
    preflight["task_local_do_not"] = Json::Value(Json::arrayValue);
    preflight["intent_amendments"] = Json::Value(Json::arrayValue);
    preflight["plan_risk_prompts"] = Json::Value(Json::arrayValue);
    preflight["stop_conditions"] = Json::Value(Json::arrayValue);

    Json::Value compliance(Json::objectValue);
    compliance["task_completion"] = "OK/WARN/VIOLATION: ";
    compliance["story_level_value"] = "OK/WARN/VIOLATION: ";
    compliance["feature_boundary"] = "OK/WARN/VIOLATION: ";
    compliance["epic_alignment"] = "OK/WARN/VIOLATION: ";
    compliance["do_not_compliance"] = Json::Value(Json::arrayValue);
    compliance["stale_solution_check"] = Json::Value(Json::arrayValue);
    compliance["validation"] = Json::Value(Json::arrayValue);
    compliance["limitations"] = Json::Value(Json::arrayValue);
    compliance["follow_up"] = Json::Value(Json::arrayValue);

    Json::Value handoff(Json::objectValue);
    handoff["target_work_item"] = stack.chain.empty() ? Json::Value(Json::nullValue) : intent_stack_item_json(stack.chain.front(), max_section_chars);
    handoff["current_authoritative_intent"] = Json::Value(Json::arrayValue);
    handoff["current_authoritative_tickets_evidence"] = Json::Value(Json::arrayValue);
    handoff["stale_or_legacy_context"] = Json::Value(Json::arrayValue);
    handoff["candidate_evidence"] = Json::Value(Json::arrayValue);
    handoff["newer_decisions_overrides"] = Json::Value(Json::arrayValue);
    handoff["do_not_non_goals"] = Json::Value(Json::arrayValue);
    handoff["execution_rules"] = Json::Value(Json::arrayValue);
    handoff["required_preflight_from_coding_agent"] = Json::Value(Json::arrayValue);
    handoff["required_final_report_from_coding_agent"] = Json::Value(Json::arrayValue);

    for (const auto& entry : stack.chain) {
        const auto& item = entry.item;
        Json::Value trace(Json::objectValue);
        trace["role"] = entry.role;
        trace["id"] = item.id;
        trace["title"] = item.title;
        trace["goal"] = bounded_text(item.goal, max_section_chars);
        preflight["intent_trace"].append(trace);

        if (item.non_goals && !trim_copy(*item.non_goals).empty()) {
            Json::Value rule(Json::objectValue);
            rule["source_id"] = item.id;
            rule["role"] = entry.role;
            rule["text"] = bounded_text(item.non_goals, max_section_chars);
            if (entry.depth == 0) {
                preflight["task_local_do_not"].append(rule);
            } else {
                preflight["inherited_do_not"].append(rule);
            }
            compliance["do_not_compliance"].append(rule);
            handoff["do_not_non_goals"].append(rule);
        }

        if (item.intent_amendments && !trim_copy(*item.intent_amendments).empty()) {
            Json::Value amendment(Json::objectValue);
            amendment["source_id"] = item.id;
            amendment["role"] = entry.role;
            amendment["text"] = bounded_text(item.intent_amendments, max_section_chars);
            preflight["intent_amendments"].append(amendment);
        }

        if (entry.depth > 0) {
            Json::Value authority(Json::objectValue);
            authority["source_id"] = item.id;
            authority["role"] = entry.role;
            authority["title"] = item.title;
            authority["goal"] = bounded_text(item.goal, max_section_chars);
            handoff["current_authoritative_intent"].append(authority);
        }

        Json::Value evidence(Json::objectValue);
        evidence["source_id"] = item.id;
        evidence["role"] = entry.role;
        evidence["state"] = to_string(item.state);
        evidence["summary"] = bounded_text(item.goal ? item.goal : item.context, max_section_chars);
        handoff["current_authoritative_tickets_evidence"].append(evidence);
    }

    preflight["candidate_related_evidence"].append("Optional KOA/Miyo/semantic provider candidates supplied by ChatGPT/operator; candidate evidence only.");
    preflight["stale_or_legacy_evidence"].append("Older tickets or proposed fixes must be labeled historical context until revalidated.");
    preflight["plan_risk_prompts"].append("Could this plan violate any Do Not item?");
    preflight["plan_risk_prompts"].append("Could this plan rely on stale architecture?");
    preflight["plan_risk_prompts"].append("Could this plan accidentally optimize only the leaf task while violating parent intent?");
    preflight["stop_conditions"].append("Stop if implementation requires violating a Do Not item.");
    preflight["stop_conditions"].append("Stop if candidate evidence conflicts and no human decision is recorded.");
    preflight["stop_conditions"].append("Stop if an old ticket's proposed fix targets obsolete architecture.");
    compliance["stale_solution_check"].append("Was any old proposed fix used?");
    compliance["stale_solution_check"].append("Was it revalidated against current architecture?");
    compliance["stale_solution_check"].append("Was any stale approach rejected?");
    compliance["validation"].append("List commands run and whether they passed.");
    compliance["limitations"].append("List unverified behavior, unresolved warnings, and any human-confirmation needs.");
    compliance["follow_up"].append("List resolution tickets, rejected stale assumptions, or human decisions still needed.");

    handoff["stale_or_legacy_context"].append("Explain which older tickets are historical context only and must not be implemented as-is.");
    handoff["candidate_evidence"].append("Explain what was retrieved semantically or indirectly and whether it is only candidate evidence.");
    handoff["newer_decisions_overrides"].append("List newer decisions that override older approaches, or 'none supplied'.");
    handoff["execution_rules"].append("Follow the current authoritative intent.");
    handoff["execution_rules"].append("Treat stale tickets as historical context only.");
    handoff["execution_rules"].append("Do not implement old proposed fixes unless revalidated.");
    handoff["execution_rules"].append("Do not infer final intent from raw backlog evidence.");
    handoff["execution_rules"].append("Stop and request human review if evidence conflicts.");
    handoff["required_preflight_from_coding_agent"].append("Restate the synthesized current intent and Do Not boundaries before editing.");
    handoff["required_preflight_from_coding_agent"].append("Confirm stale/candidate evidence is not being used as execution authority.");
    handoff["required_final_report_from_coding_agent"].append("Report Do Not compliance, stale solution checks, validation, limitations, and follow-ups.");

    if (template_kind == "preflight" || template_kind == "both" || template_kind == "all") {
        payload["preflight"] = preflight;
    }
    if (template_kind == "compliance" || template_kind == "both" || template_kind == "all") {
        payload["compliance"] = compliance;
    }
    if (template_kind == "handoff" || template_kind == "all") {
        payload["coding_agent_intent_prompt"] = handoff;
    }
    return payload;
}

void print_intent_template_text(
    const IntentStackResult& stack,
    const std::string& template_kind,
    std::size_t max_section_chars
) {
    const auto print_trace = [&]() {
        std::cout << "## Intent Trace\n";
        std::cout << "- Current Task: ";
        bool printed_current = false;
        for (const auto& entry : stack.chain) {
            if (entry.depth == 0) {
                std::cout << entry.item.id << " - " << entry.item.title << "\n";
                printed_current = true;
                break;
            }
        }
        if (!printed_current) {
            std::cout << "unresolved\n";
        }
        const auto print_role = [&](const std::string& label, const std::string& role) {
            std::cout << "- " << label << ": ";
            for (const auto& entry : stack.chain) {
                if (entry.role == role) {
                    std::cout << entry.item.id << " - " << entry.item.title << "\n";
                    return;
                }
            }
            std::cout << "missing / unresolved\n";
        };
        print_role("Parent Story", "story");
        print_role("Parent Feature", "feature");
        print_role("Parent Epic", "epic");
        std::cout << "- Trace Depth: " << stack.chain.size() << "\n";
        std::cout << "- Missing / unresolved ancestors: " << (stack.warnings.empty() ? "none" : join_strings(stack.warnings, "; ")) << "\n";
        std::cout << "\n### Current Authoritative Intent\n";
        for (const auto& entry : stack.chain) {
            const auto& item = entry.item;
            std::cout << "- [" << entry.role << "] " << item.id << " - " << item.title << "\n";
            if (const auto goal = bounded_text(item.goal, max_section_chars); !goal.empty()) {
                std::cout << "  goal: " << goal << "\n";
            }
        }
    };

    const auto print_do_not = [&]() {
        std::cout << "## Inherited Do Not\n";
        bool inherited = false;
        for (const auto& entry : stack.chain) {
            if (entry.depth == 0 || !entry.item.non_goals || trim_copy(*entry.item.non_goals).empty()) {
                continue;
            }
            inherited = true;
            std::cout << "- " << entry.item.id << " (" << entry.role << "): " << bounded_text(entry.item.non_goals, max_section_chars) << "\n";
        }
        if (!inherited) {
            std::cout << "- none recorded\n";
        }
        std::cout << "## Task-Local Do Not\n";
        if (!stack.chain.empty() && stack.chain.front().item.non_goals && !trim_copy(*stack.chain.front().item.non_goals).empty()) {
            std::cout << "- " << bounded_text(stack.chain.front().item.non_goals, max_section_chars) << "\n";
        } else {
            std::cout << "- none recorded\n";
        }
    };

    const auto print_amendments = [&]() {
        std::cout << "## Intent Amendments\n";
        bool found = false;
        for (const auto& entry : stack.chain) {
            if (!entry.item.intent_amendments || trim_copy(*entry.item.intent_amendments).empty()) {
                continue;
            }
            found = true;
            std::cout << "- " << entry.item.id << " (" << entry.role << "): " << bounded_text(entry.item.intent_amendments, max_section_chars) << "\n";
        }
        if (!found) {
            std::cout << "- none recorded\n";
        }
    };

    if (template_kind == "preflight" || template_kind == "both" || template_kind == "all") {
        std::cout << "# Intent Preflight\n\n";
        print_trace();
        print_do_not();
        print_amendments();
        std::cout << "## Candidate / Related Evidence\n";
        std::cout << "- Optional KOA/Miyo/semantic provider candidates supplied by ChatGPT/operator; candidate evidence only.\n";
        std::cout << "## Stale or Legacy Evidence\n";
        std::cout << "- Older tickets or proposed fixes must be labeled historical context until revalidated.\n";
        std::cout << "## Plan Risk Prompts\n";
        std::cout << "- Could this plan violate any Do Not item?\n";
        std::cout << "- Could this plan rely on stale architecture?\n";
        std::cout << "- Could this plan accidentally optimize only the leaf task while violating parent intent?\n";
        std::cout << "## Stop Conditions\n";
        std::cout << "- Stop if implementation requires violating a Do Not item.\n";
        std::cout << "- Stop if candidate evidence conflicts and no human decision is recorded.\n";
        std::cout << "- Stop if an old ticket's proposed fix targets obsolete architecture.\n\n";
    }

    if (template_kind == "compliance" || template_kind == "both" || template_kind == "all") {
        std::cout << "# Do Not Compliance Report\n\n";
        std::cout << "## Task Completion\n";
        std::cout << "- OK/WARN/VIOLATION: \n";
        std::cout << "## Story-level Value\n";
        std::cout << "- OK/WARN/VIOLATION: \n";
        std::cout << "## Feature Boundary\n";
        std::cout << "- OK/WARN/VIOLATION: \n";
        std::cout << "## Epic Alignment\n";
        for (const auto& entry : stack.chain) {
            if (entry.depth == 0) {
                continue;
            }
            std::cout << "- " << entry.item.id << " (" << entry.role << "): OK/WARN/VIOLATION: \n";
        }
        if (stack.chain.size() <= 1) {
            std::cout << "- no resolved parent chain\n";
        }
        std::cout << "## Do Not Compliance\n";
        bool has_rules = false;
        for (const auto& entry : stack.chain) {
            if (!entry.item.non_goals || trim_copy(*entry.item.non_goals).empty()) {
                continue;
            }
            has_rules = true;
            std::cout << "- " << entry.item.id << ": OK/WARN/VIOLATION: " << bounded_text(entry.item.non_goals, max_section_chars) << "\n";
        }
        if (!has_rules) {
            std::cout << "- no Do Not constraints recorded\n";
        }
        std::cout << "## Stale Solution Check\n";
        std::cout << "- Was any old proposed fix used?\n";
        std::cout << "- Was it revalidated against current architecture?\n";
        std::cout << "- Was any stale approach rejected?\n";
        std::cout << "## Validation\n";
        std::cout << "- commands run: \n";
        std::cout << "## Limitations\n";
        std::cout << "- unverified behavior / unresolved warnings: \n";
        std::cout << "## Follow-up\n";
        std::cout << "- resolution tickets / human decisions still needed: \n";
    }

    if (template_kind == "handoff" || template_kind == "all") {
        std::cout << "# Coding Agent Intent Prompt\n\n";
        std::cout << "## Target Work Item\n";
        if (!stack.chain.empty()) {
            const auto& item = stack.chain.front().item;
            std::cout << "- " << item.id << " - " << item.title << "\n";
        } else {
            std::cout << "- unresolved\n";
        }
        std::cout << "## Current Authoritative Intent\n";
        for (const auto& entry : stack.chain) {
            std::cout << "- " << entry.item.id << " (" << entry.role << "): " << bounded_text(entry.item.goal ? entry.item.goal : entry.item.context, max_section_chars) << "\n";
        }
        std::cout << "## Current Authoritative Tickets / Evidence\n";
        for (const auto& entry : stack.chain) {
            std::cout << "- " << entry.item.id << " (" << entry.role << ", state=" << to_string(entry.item.state) << ")\n";
        }
        std::cout << "## Stale or Legacy Context\n";
        std::cout << "Explain which older tickets are historical context only and must not be implemented as-is.\n";
        std::cout << "## Candidate Evidence\n";
        std::cout << "Explain what was retrieved semantically or indirectly and whether it is only candidate evidence.\n";
        std::cout << "## Newer Decisions That Override Older Approaches\n";
        std::cout << "- none supplied by KOB; ChatGPT/human must label any overrides before handoff.\n";
        std::cout << "## Do Not / Non-Goals\n";
        print_do_not();
        std::cout << "## Execution Rules\n";
        std::cout << "- Follow the current authoritative intent.\n";
        std::cout << "- Treat stale tickets as historical context only.\n";
        std::cout << "- Do not implement old proposed fixes unless revalidated.\n";
        std::cout << "- Do not infer final intent from raw backlog evidence.\n";
        std::cout << "- Stop and request human review if evidence conflicts.\n";
        std::cout << "## Required Preflight From Coding Agent\n";
        std::cout << "- Restate the synthesized current intent and Do Not boundaries before editing.\n";
        std::cout << "- Confirm stale/candidate evidence is not being used as execution authority.\n";
        std::cout << "## Required Final Report From Coding Agent\n";
        std::cout << "- Report Do Not compliance, stale solution checks, validation, limitations, and follow-ups.\n";
    }
}

std::string intent_amendment_guidance(ItemState state) {
    switch (state) {
        case ItemState::Proposed:
        case ItemState::Planned:
        case ItemState::Ready:
            return "Clarify Ready fields directly when this changes executable scope; otherwise keep as amendment evidence.";
        case ItemState::InProgress:
            return "Needs replan: pause implementation, regenerate preflight, and resume only after the correction is acknowledged.";
        case ItemState::Review:
            return "Drift finding: resolve explicitly before Done, or create an Intent Drift Resolution ticket if scope changed.";
        case ItemState::Done:
            return "Post-done drift: consider reopen, corrective bug, or follow-up task based on violation severity.";
        case ItemState::New:
            return "Clarify item before dispatching work.";
        case ItemState::Blocked:
            return "Keep blocker visible and re-evaluate before unblocking work.";
        case ItemState::Dropped:
            return "Dropped item amended for audit only; create a new item before execution.";
    }
    return "Review amendment before continuing work.";
}

std::string format_intent_amendment_entry(
    const BacklogItem& item,
    const std::string& agent,
    const std::string& correction,
    const std::string& reason,
    const std::vector<std::string>& applies_to
) {
    std::ostringstream out;
    out << "- timestamp: " << current_utc_timestamp() << "\n";
    out << "  author: " << agent << "\n";
    out << "  state: " << to_string(item.state) << "\n";
    out << "  applies_to: " << (applies_to.empty() ? "unspecified" : join_strings(applies_to, ", ")) << "\n";
    out << "  reason: " << reason << "\n";
    out << "  correction: " << correction << "\n";
    out << "  follow_up: " << intent_amendment_guidance(item.state);
    return out.str();
}

std::string join_or_none(const std::vector<std::string>& values) {
    return values.empty() ? "none" : join_strings(values, ", ");
}

bool is_item_index_markdown(const std::filesystem::path& path) {
    return path.filename().generic_string().find(".index.md") != std::string::npos;
}

std::vector<std::string> collect_child_item_ids(CanonicalStore& store, const std::string& source_id) {
    std::vector<std::string> children;
    for (const auto& path : store.list_items()) {
        if (is_item_index_markdown(path)) {
            continue;
        }
        const auto candidate = store.read(path);
        if (candidate.parent && trim_copy(*candidate.parent) == source_id) {
            children.push_back(candidate.id);
        }
    }
    return children;
}

bool looks_like_cli_path_ref(const std::string& ref) {
    const auto lower = lower_copy(trim_copy(ref));
    return lower.find('/') != std::string::npos ||
           lower.find('\\') != std::string::npos ||
           lower.find(':') != std::string::npos ||
           (lower.size() >= 3 && lower.substr(lower.size() - 3) == ".md");
}

void reject_outside_product_path_ref(const std::string& ref, const std::filesystem::path& product_root) {
    if (!looks_like_cli_path_ref(ref)) {
        return;
    }
    const auto path = expand_user_path(ref);
    if (!is_inside_path(path, product_root)) {
        throw std::runtime_error("Item path ref is outside active product root: " + ref);
    }
}

void require_item_file_inside_product(const BacklogItem& item, const std::filesystem::path& product_root) {
    if (!item.file_path) {
        throw std::runtime_error("Resolved item has no file path: " + item.id);
    }
    if (!is_inside_path(*item.file_path, product_root)) {
        throw std::runtime_error("Resolved item file is outside active product root: " + item.id);
    }
}

std::vector<std::string> collect_sibling_item_ids(CanonicalStore& store, const BacklogItem& source) {
    std::vector<std::string> siblings;
    if (!source.parent || trim_copy(*source.parent).empty()) {
        return siblings;
    }
    const auto source_parent = trim_copy(*source.parent);
    for (const auto& path : store.list_items()) {
        if (is_item_index_markdown(path)) {
            continue;
        }
        const auto candidate = store.read(path);
        if (candidate.id == source.id) {
            continue;
        }
        if (candidate.parent && trim_copy(*candidate.parent) == source_parent) {
            siblings.push_back(candidate.id);
        }
    }
    return siblings;
}

std::vector<std::string> parent_related_ids(const IntentStackResult& stack) {
    for (const auto& entry : stack.chain) {
        if (entry.depth == 1) {
            return entry.item.links.relates;
        }
    }
    return {};
}

std::vector<std::string> matching_worklog_lines(const BacklogItem& item, const std::vector<std::string>& needles, std::size_t max_lines) {
    std::vector<std::string> matches;
    for (const auto& line : item.worklog) {
        const auto lower = lower_copy(line);
        const bool found = std::any_of(needles.begin(), needles.end(), [&](const std::string& needle) {
            return lower.find(needle) != std::string::npos;
        });
        if (found) {
            matches.push_back(line);
            if (matches.size() >= max_lines) {
                break;
            }
        }
    }
    return matches;
}

std::vector<std::string> recent_worklog_lines(const BacklogItem& item, std::size_t max_lines) {
    std::vector<std::string> lines;
    const auto count = item.worklog.size();
    const auto start = count > max_lines ? count - max_lines : 0;
    for (std::size_t i = start; i < count; ++i) {
        lines.push_back(item.worklog[i]);
    }
    return lines;
}

std::vector<std::string> stale_intent_terms(const BacklogItem& item) {
    std::string haystack = item.title + "\n";
    const std::vector<std::optional<std::string>> sections = {
        item.context,
        item.goal,
        item.approach,
        item.acceptance_criteria,
        item.risks,
        item.intent_amendments,
    };
    for (const auto& section : sections) {
        if (section) {
            haystack += *section + "\n";
        }
    }
    haystack += join_worklog_lines(item.worklog);
    const auto lower = lower_copy(haystack);
    const std::vector<std::string> terms = {
        "stale",
        "legacy",
        "obsolete",
        "superseded",
        "old architecture",
        "old release",
        "v0.0.4",
        "0.0.4",
    };
    std::vector<std::string> found;
    for (const auto& term : terms) {
        if (lower.find(term) != std::string::npos) {
            found.push_back(term);
        }
    }
    return found;
}

Json::Value json_array_from_strings(const std::vector<std::string>& values) {
    Json::Value array(Json::arrayValue);
    for (const auto& value : values) {
        array.append(value);
    }
    return array;
}

std::string normalize_drift_result(std::string value) {
    value = lower_copy(trim_copy(value));
    if (value == "none" || value == "no_drift") {
        return "no-drift";
    }
    if (value == "drift-detected") {
        return "drift";
    }
    if (value == "unknown" || value == "needs-human-confirmation") {
        return "uncertain";
    }
    if (value == "no-drift" || value == "drift" || value == "uncertain") {
        return value;
    }
    return "uncertain";
}

Json::Value drift_resolution_template_json(
    const BacklogItem& source,
    const IntentStackResult& stack,
    const std::vector<std::string>& children,
    const std::string& detection_stage,
    const std::string& detected_by,
    const std::string& drift_type,
    std::size_t max_section_chars
) {
    Json::Value payload(Json::objectValue);
    payload["workflow_rule"] = "detected drift is not execution permission";
    payload["source_item"]["id"] = source.id;
    payload["source_item"]["title"] = source.title;
    payload["source_item"]["state"] = to_string(source.state);
    payload["source_item"]["parent"] = source.parent ? Json::Value(*source.parent) : Json::Value(Json::nullValue);
    payload["detection"]["detection_stage"] = detection_stage;
    payload["detection"]["detected_by"] = detected_by;
    payload["detection"]["drift_type"] = drift_type;
    payload["detection"]["why_this_is_drift"] = "Human/ChatGPT must summarize why current evidence changes the executable boundary.";
    payload["evidence_pack"]["current_authoritative_evidence"] = intent_stack_json(stack, max_section_chars);
    payload["evidence_pack"]["stale_legacy_evidence"] = "List older tickets/proposed fixes preserved as evidence only.";
    payload["evidence_pack"]["candidate_evidence"] = "List optional provider-backed semantic candidates; candidate evidence only.";
    payload["evidence_pack"]["conflicting_evidence"] = "List conflicts requiring human confirmation.";
    payload["evidence_pack"]["missing_evidence"] = "List unresolved parent, relation, or contract evidence.";
    payload["relationship_map"]["parent_chain"] = Json::Value(Json::arrayValue);
    for (const auto& entry : stack.chain) {
        payload["relationship_map"]["parent_chain"].append(entry.item.id + " (" + entry.role + ")");
    }
    payload["relationship_map"]["children"] = json_array_from_strings(children);
    payload["relationship_map"]["explicit_relates"] = json_array_from_strings(source.links.relates);
    payload["relationship_map"]["semantic_candidates"] = "Provider supplied; not generated by KOB core.";
    payload["human_confirmation"]["decision"] = "required before execution";
    payload["human_confirmation"]["confirmed_current_intent"] = "";
    payload["human_confirmation"]["rejected_stale_assumptions"] = "";
    payload["human_confirmation"]["unresolved_questions"] = "";
    payload["goal"] = "Resolve confirmed intent drift from " + source.id + ".";
    payload["non_goals_do_not"] = "Do not execute from the original item; do not use stale proposed fixes unless revalidated.";
    payload["approach"] = "Use this resolution ticket as the executable boundary after human confirmation.";
    payload["acceptance_criteria"] = "Evidence is labeled current/stale/candidate/conflicting, human decision is recorded, and validation plan passes.";
    payload["stop_conditions"] = "Stop if evidence conflicts, human confirmation is missing, or execution would violate Do Not boundaries.";
    payload["validation_plan"] = "Run the affected implementation validation and report limitations.";
    payload["links"]["relates"] = source.id;
    return payload;
}

void print_drift_resolution_template_text(
    const BacklogItem& source,
    const IntentStackResult& stack,
    const std::vector<std::string>& children,
    const std::string& detection_stage,
    const std::string& detected_by,
    const std::string& drift_type,
    std::size_t max_section_chars
) {
    std::cout << "# Intent Drift Resolution Ticket Template\n\n";
    std::cout << "Detected drift is not execution permission. The original item preserves history; the new Intent Drift Resolution ticket becomes the executable boundary.\n\n";
    std::cout << "## Source Item\n";
    std::cout << "- id: " << source.id << "\n";
    std::cout << "- title: " << source.title << "\n";
    std::cout << "- state: " << to_string(source.state) << "\n";
    std::cout << "- parent: " << (source.parent ? *source.parent : "none") << "\n";
    std::cout << "## Detection\n";
    std::cout << "- detection stage: " << detection_stage << "\n";
    std::cout << "- detected by: " << detected_by << "\n";
    std::cout << "- drift type: " << drift_type << "\n";
    std::cout << "- why this is drift: <human/ChatGPT summary required>\n";
    std::cout << "## Evidence Pack\n";
    std::cout << "- current authoritative evidence: ";
    for (const auto& entry : stack.chain) {
        std::cout << entry.item.id << " (" << entry.role << ") ";
    }
    std::cout << "\n";
    std::cout << "- stale / legacy evidence: <older tickets/proposed fixes preserved as evidence only>\n";
    std::cout << "- candidate evidence: <provider-backed semantic/indirect candidates; candidate only>\n";
    std::cout << "- conflicting evidence: <conflicts requiring human confirmation>\n";
    std::cout << "- missing evidence: " << (stack.warnings.empty() ? "none from deterministic parent chain" : join_strings(stack.warnings, "; ")) << "\n";
    std::cout << "## Relationship Map\n";
    std::cout << "- parent chain: ";
    for (const auto& entry : stack.chain) {
        std::cout << entry.item.id << " (" << entry.role << ") ";
    }
    std::cout << "\n";
    std::cout << "- children: " << join_or_none(children) << "\n";
    std::cout << "- explicit relates: " << join_or_none(source.links.relates) << "\n";
    std::cout << "- parent relates: <inspect parent related tickets before handoff>\n";
    std::cout << "- semantic candidates: <optional provider evidence; not generated by KOB core>\n";
    std::cout << "- superseded / duplicate / related done items: <label if known>\n";
    std::cout << "## Human Confirmation\n";
    std::cout << "- decision: required before execution\n";
    std::cout << "- confirmed current intent: \n";
    std::cout << "- rejected stale assumptions: \n";
    std::cout << "- unresolved questions: \n";
    std::cout << "## Goal\nResolve confirmed intent drift from " << source.id << ".\n";
    std::cout << "## Non-Goals / Do Not\n";
    std::cout << "- Do not execute from the original item.\n";
    std::cout << "- Do not use stale proposed fixes unless revalidated.\n";
    if (source.non_goals && !trim_copy(*source.non_goals).empty()) {
        std::cout << "- Source Do Not: " << bounded_text(source.non_goals, max_section_chars) << "\n";
    }
    std::cout << "## Approach\nUse this resolution ticket as the executable boundary after human confirmation.\n";
    std::cout << "## Acceptance Criteria\n- Evidence is labeled current/stale/candidate/conflicting.\n- Human decision is recorded.\n- Validation plan passes.\n";
    std::cout << "## Stop Conditions\n- Stop if evidence conflicts and no human decision is recorded.\n- Stop if execution would violate Do Not boundaries.\n";
    std::cout << "## Validation Plan\n- Run affected implementation validation and report limitations.\n";
    std::cout << "## Links\n- relates: " << source.id << "\n";
}

